mapper.select:
SELECT
cr.room_id, cr.room_name, cr.required_members, cr.current_members, cr.status, cr.create_time,
u_creator.user_id AS creator_user_id, u_creator.username AS creator_username, u_creator.avatar AS creator_avatar
FROM chat_games cr
LEFT JOIN sys_user u_creator ON cr.creator_id = u_creator.user_id

    AND cr.room_name LIKE CONCAT('%', #{roomName}, '%')
    AND cr.status = #{status}
    AND cr.required_members >= #{requiredMembers}
    AND cr.current_members = #{currentMembers}
    AND cr.create_time = #{createTime}

ORDER BY cr.create_time DESC

SELECT
cr.room_id, cr.room_name, cr.required_members, cr.current_members, cr.status, cr.create_time,
u_creator.user_id AS creator_user_id, u_creator.username AS creator_username, u_creator.avatar AS creator_avatar
FROM chat_games cr
LEFT JOIN sys_user u_creator ON cr.creator_id = u_creator.user_id

    AND cr.room_name LIKE CONCAT('%', #{roomName}, '%')
    AND cr.status = #{status}
    AND cr.required_members >= #{requiredMembers}
    AND cr.current_members = #{currentMembers}
    AND cr.create_time = #{createTime}
    AND cr.need_invite = false

ORDER BY cr.create_time DESC
